using Microsoft.Extensions.Options;
using Microsoft.Playwright;
using ScraperBackendService.Configuration;
using ScraperBackendService.Core.Net;
using ScraperBackendService.Browser;
using System.Net;

namespace ScraperBackendService.Extensions;/// <summary>/// Service registration extension methods for dependency injection configuration./// </summary>public static class ServiceCollectionExtensions{    public static IServiceCollection AddScrapingServices(this IServiceCollection services, ServiceConfiguration config)    {        // Register the fully-populated configuration instance directly.        // Previous manual property copy was missing ManualChallenge*, Cookie*, Cache* fields.        services.AddSingleton<IOptions<ServiceConfiguration>>(Options.Create(config));        // Register PlaywrightService as singleton to manage browser lifecycle        services.AddSingleton<PlaywrightService>();        // Register Playwright browser as singleton.        // PlaywrightService kicks off async init in its constructor; we block here        // during startup only (no SynchronizationContext in ASP.NET Core).        // A timeout guard prevents hanging indefinitely if Chromium fails to launch.        services.AddSingleton<IBrowser>(sp =>        {            var playwrightService = sp.GetRequiredService<PlaywrightService>();            var task = playwrightService.GetBrowserAsync();            if (!task.Wait(TimeSpan.FromSeconds(60)))                throw new TimeoutException("Playwright browser initialization timed out after 60 seconds");            return task.GetAwaiter().GetResult();        });        // Register PlaywrightContextManager as singleton using the browser instance        services.AddSingleton<PlaywrightContextManager>(sp =>        {            var browser = sp.GetRequiredService<IBrowser>();            var logger = sp.GetRequiredService<ILogger<PlaywrightContextManager>>();            var options = new PlaywrightClientOptions            {                ChallengeAutoWaitMs = config.ChallengeAutoWaitSeconds * 1000,                ChallengeAutoWaitSlowMs = config.ChallengeAutoWaitSlowSeconds * 1000,                EnableManualChallengeResolution = config.EnableManualChallengeResolution,                ManualChallengeTimeoutSeconds = config.ManualChallengeTimeoutSeconds,                ManualChallengeWindowWidth = config.ManualChallengeWindowWidth,                ManualChallengeWindowHeight = config.ManualChallengeWindowHeight,                EnableCookiePersistence = config.EnableCookiePersistence,                AutoLoadCookiesOnContextCreation = config.AutoLoadCookiesOnContextCreation,                CookieStorageDirectory = config.CookieStorageDirectory            };            return new PlaywrightContextManager(browser, logger, options);        });        // Register ChallengeDetector        services.AddSingleton<ChallengeDetector>(sp => {            var logger = sp.GetRequiredService<ILogger<ChallengeDetector>>();            return new ChallengeDetector(logger);        });        // Register PlaywrightNetworkClient using context manager        services.AddScoped<PlaywrightNetworkClient>(sp =>        {            var ctxMgr = sp.GetRequiredService<PlaywrightContextManager>();            var logger = sp.GetRequiredService<ILogger<PlaywrightNetworkClient>>();            var detector = sp.GetRequiredService<ChallengeDetector>();            return new PlaywrightNetworkClient(ctxMgr, logger, detector);        });        // Register HttpNetworkClient via IHttpClientFactory with optimized SocketsHttpHandler.        // Configuring here (not in CreateDefaultClient) ensures DI-injected clients        // actually use these settings; CreateDefaultClient() covers manual instantiation only.        services.AddHttpClient<HttpNetworkClient>(http =>        {            http.Timeout = TimeSpan.FromSeconds(30);            http.DefaultRequestHeaders.UserAgent.ParseAdd(                "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/118 Safari/537.36");            http.DefaultRequestHeaders.Accept.ParseAdd(                "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8");            http.DefaultRequestHeaders.AcceptLanguage.ParseAdd(                "en-US,en;q=0.9,ja;q=0.8,zh-CN;q=0.7");        })        .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler        {            AutomaticDecompression = DecompressionMethods.GZip | DecompressionMethods.Deflate | DecompressionMethods.Brotli,            PooledConnectionLifetime = TimeSpan.FromMinutes(10),            PooledConnectionIdleTimeout = TimeSpan.FromSeconds(90),            MaxConnectionsPerServer = 12,            EnableMultipleHttp2Connections = true,            UseCookies = false        });        // =============== Register All Providers ===============        // Provider registration is managed by ProviderRegistry        foreach (var providerConfig in Providers._Registry.ProviderRegistry.GetAllProviders())        {            Providers._Registry.ProviderRegistry.RegisterProvider(services, providerConfig, config);        }
        return services;
    }
}